     1→/**
     2→ * Full-text search: pre-built JSON index embedded as inline JS.
     3→ * Vanilla JS substring search, no external library.
     4→ */
     5→
     6→import type { ManifestEntry } from '../../types/transcript.js'
     7→import type { SearchIndexEntry } from '../../types/report.js'
     8→import { escHtml, htmlShell, renderNav } from './layout.js'
     9→
    10→const MAX_INDEX_BYTES = 50_000
    11→const SNIPPET_LEN = 200
    12→
    13→// ---------------------------------------------------------------------------
    14→// Index construction
    15→// ---------------------------------------------------------------------------
    16→
    17→export function buildSearchIndex(
    18→  manifests: ManifestEntry[],
    19→  getSnippet: (m: ManifestEntry) => string,
    20→): SearchIndexEntry[] {
    21→  const entries: SearchIndexEntry[] = []
    22→  let totalBytes = 0
    23→
    24→  for (const m of manifests) {
    25→    let snippet = getSnippet(m).slice(0, SNIPPET_LEN)
    26→    const entry: SearchIndexEntry = {
    27→      url: transcriptUrl(m),
    28→      title: m.title || m.session_id,
    29→      client: m.client,
    30→      date: m.started_at.slice(0, 10),
    31→      snippet,
    32→    }
    33→    const entryBytes = JSON.stringify(entry).length
    34→    if (totalBytes + entryBytes > MAX_INDEX_BYTES) {
    35→      // Truncate snippet to fit within budget
    36→      const remaining = MAX_INDEX_BYTES - totalBytes - (entryBytes - snippet.length) - 10
    37→      if (remaining < 20) break
    38→      snippet = snippet.slice(0, remaining)
    39→      entry.snippet = snippet
    40→    }
    41→    totalBytes += JSON.stringify(entry).length
    42→    entries.push(entry)
    43→  }
    44→
    45→  return entries
    46→}
    47→
    48→function transcriptUrl(m: ManifestEntry): string {
    49→  const client = m.client || 'unknown'
    50→  // Build relative URL from search.html to transcript page
    51→  // search.html is at root level, transcript pages at transcripts/{client}/{stem}.html
    52→  const cleanPath = m.repo_clean_path || m.global_clean_path || ''
    53→  const stem = cleanPath ? cleanPath.replace(/.*\//, '').replace(/\.md$/, '') : m.session_id
    54→  return `transcripts/${client}/${stem}.html`
    55→}
    56→
    57→// ---------------------------------------------------------------------------
    58→// Search page renderer
    59→// ---------------------------------------------------------------------------
    60→
    61→export function renderSearchPage(index: SearchIndexEntry[]): string {
    62→  const indexJson = JSON.stringify(index)
    63→  const nav = renderNav('search', true)
    64→
    65→  const extraHead = `<script>
    66→const SEARCH_INDEX = ${indexJson};
    67→</script>`
    68→
    69→  const content = `
    70→<div class="page-header">
    71→  <h1>Search</h1>
    72→  <p class="subtitle">Full-text search across all imported sessions</p>
    73→</div>
    74→
    75→<input
    76→  type="search"
    77→  id="search-input"
    78→  class="search-box"
    79→  placeholder="Search sessions, messages, and content..."
    80→  autofocus
    81→>
    82→<div id="search-count"></div>
    83→<div id="search-results" class="search-results"></div>
    84→
    85→<script>
    86→(function() {
    87→  const input = document.getElementById('search-input');
    88→  const resultsEl = document.getElementById('search-results');
    89→  const countEl = document.getElementById('search-count');
    90→
    91→  function highlight(text, query) {
    92→    if (!query) return escHtml(text);
    93→    const escaped = escHtml(text);
    94→    const escapedQ = escHtml(query);
    95→    const lower = escaped.toLowerCase();
    96→    const lowerQ = escapedQ.toLowerCase();
    97→    if (!lowerQ) return escaped;
    98→    let result = '';
    99→    let i = 0;
   100→    while (i < escaped.length) {
   101→      const idx = lower.indexOf(lowerQ, i);
   102→      if (idx === -1) { result += escaped.slice(i); break; }
   103→      result += escaped.slice(i, idx) + '<mark>' + escaped.slice(idx, idx + lowerQ.length) + '</mark>';
   104→      i = idx + lowerQ.length;
   105→    }
   106→    return result;
   107→  }
   108→
   109→  function escHtml(s) {
   110→    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
   111→  }
   112→
   113→  function renderResults(query) {
   114→    const q = (query || '').toLowerCase().trim();
   115→    if (!q) {
   116→      resultsEl.innerHTML = '';
   117→      countEl.textContent = SEARCH_INDEX.length + ' session(s) indexed';
   118→      return;
   119→    }
   120→    const matches = SEARCH_INDEX.filter(function(e) {
   121→      return (e.title || '').toLowerCase().includes(q) ||
   122→             (e.snippet || '').toLowerCase().includes(q) ||
   123→             (e.client || '').toLowerCase().includes(q);
   124→    });
   125→    countEl.textContent = matches.length + ' result(s) for "' + escHtml(q) + '"';
   126→    resultsEl.innerHTML = matches.map(function(e) {
   127→      return '<div class="search-result">' +
   128→        '<div class="search-result-title"><a href="' + escHtml(e.url) + '">' + highlight(e.title, query) + '</a></div>' +
   129→        '<div class="search-result-meta"><span class="badge badge-' + escHtml(e.client) + '">' + escHtml(e.client) + '</span> &nbsp; ' + escHtml(e.date) + '</div>' +
   130→        '<div class="search-result-snippet">' + highlight(e.snippet, query) + '</div>' +
   131→        '</div>';
   132→    }).join('');
   133→  }
   134→
   135→  renderResults('');
   136→  input.addEventListener('input', function() { renderResults(input.value); });
   137→})();
   138→</script>`
   139→
   140→  return htmlShell('Search', content, nav, extraHead)
   141→}
